19	type Story = StoryObj<typeof meta>;
20	
21	export const Render: Story = {
22	    args: {
23	        name: 'John Doe',
24	        email: 'john.doe@example.com',
25	        token: 'example-token',
26	    },
27	    parameters: {
28	        msw: {
29	            handlers: [
30	                http.post('*/api/auth/sign-up/email', async ({ request }) => {
31	                    const payload = await request.json();
32	                    signUpEmailSpy(payload);
33	                    return HttpResponse.json({
34	                        token: null,
35	                        user: {
36	                            id: '123x',
37	                            name: 'John Doe',
38	                            email: 'john.doe@example.com',
39	                            createdAt: new Date().toISOString(),
40	                            updatedAt: new Date().toISOString(),
41	                            emailVerified: false,
42	                            image: null,
43	                        },
44	                    });
45	                }),
46	            ],
47	        },
48	    },
49	};
50	
51	export const ValidSubmit: Story = {
52	    ...Render,
53	    play: async function ({ canvasElement, userEvent, viewMode }) {
54	        if (viewMode === 'docs') return;
55	
56	        signUpEmailSpy.mockClear();
57	
58	        const canvas = within(canvasElement);
59	        const password = await canvas.findByLabelText(/^Password/i);
60	        const confirmPassword = await canvas.findByLabelText(/Confirm password/i);
61	        const submitButton = await canvas.findByRole('button', { name: /Create login/i });
62	
63	        await userEvent.clear(password);
64	        await userEvent.type(password, 'validPassword123');
65	        await userEvent.clear(confirmPassword);
66	        await userEvent.type(confirmPassword, 'validPassword123');
67	        await userEvent.click(submitButton);
68	
69	        await waitFor(() => expect(signUpEmailSpy).toHaveBeenCalled());
70	        const firstCallArg = signUpEmailSpy.mock.calls[0][0] as {
71	            name: string;
72	            email: string;
73	            password: string;
74	        };
75	        // The story should pass the args email/name plus the entered password to signUp.email.
76	        await expect(firstCallArg).toEqual({
77	            name: 'John Doe',
78	            email: 'john.doe@example.com',
79	            password: 'validPassword123',
80	        });
81	    },
82	};
83	
84	export const InvalidSubmit: Story = {
85	    ...Render,
86	    play: async function ({ canvasElement, userEvent, viewMode }) {
87	        if (viewMode === 'docs') return;
88	
89	        const canvas = within(canvasElement);
90	        const password = await canvas.findByLabelText(/^Password/i);
91	        const confirmPassword = await canvas.findByLabelText(/Confirm password/i);
92	        const submitButton = await canvas.findByRole('button', { name: /Create login/i });
93	
94	        await userEvent.clear(password);
95	        await userEvent.type(password, 'validPassword123');
96	        await userEvent.clear(confirmPassword);
97	        await userEvent.type(confirmPassword, 'doofusPassword789');
98	        await userEvent.click(submitButton);
99	
100	        // Mantine duplicates the error text in the label and the error element, so assert via aria-describedby.
101	        const errorId = confirmPassword.getAttribute('aria-describedby');
102	        if (!errorId) {
103	            throw new Error('Expected confirm password input to have aria-describedby pointing at the error element');
104	        }
105	
106	        // Mantine may render the error element outside the story canvas (portal).
107	        // Try the canvas first, then fall back to the global document by id.
108	        let errorEl = canvasElement.querySelector<HTMLElement>(`#${CSS.escape(errorId)}`);
109	        errorEl ??= document.getElementById(errorId);
110	
111	        if (!errorEl) {
