28	
29	export interface Props {
30	    name: string
31	    email: string;
32	    token: string;
33	}
34	
35	const ClaimSignupSchema = z.object({
36	    password: z.string().min(8, { message: 'Password must be at least 8 characters long' }),
37	    confirmPassword: z.string().min(1, { message: 'Please confirm your password' }),
38	}).refine((data) => data.password === data.confirmPassword, {
39	    message: 'Passwords do not match',
40	    path: ['confirmPassword'],
41	});
42	
43	export const ClaimSignup = ({ name, email, token }: Props) => {
44	    const [loading, setLoading] = useState(false);
45	    const [signupError, setSignupError] = useState<boolean>(false);
46	    const router = useRouter();
47	    const redirectPath = `/api/footy/auth/claim/${encodeURIComponent(token)}?redirect=/footy/profile`;
48	    const socialRedirect = new URL(redirectPath, getPublicBaseUrl()).toString();
49	
50	    const form = useForm({
51	        initialValues: {
52	            password: '',
53	            confirmPassword: '',
54	        },
55	        validate: zod4Resolver(ClaimSignupSchema),
56	        validateInputOnBlur: true,
57	    });
58	
59	    const handleSignUp = async (values: z.infer<typeof ClaimSignupSchema>) => {
60	        setLoading(true);
61	        setSignupError(false);
62	
63	        try {
64	            await authClient.signUp.email({
65	                name: name,
66	                email: email,
67	                password: values.password,
68	            }, {
69	                onError: (ctx) => {
70	                    alert(ctx.error.message);
71	                },
72	            });
73	
74	            router.push(redirectPath);
75	        } catch (error) {
76	            captureUnexpectedError(error, {
77	                layer: 'client',
78	                action: 'signUpWithEmail',
79	                component: 'ClaimSignup',
80	                route: '/claim-signup',
81	                extra: {
82	                    redirectPath,
83	                },
84	            });
85	            setSignupError(true);
86	        } finally {
87	            setLoading(false);
88	        }
89	    };
90	
91	    const errorNotification = signupError ? (
92	        <Notification
93	            icon={<IconX size={config.notificationIconSize} />}
94	            color="red"
