25	        token: 'token-123',
26	    };
27	    const redirectPath = `/api/footy/auth/claim/${encodeURIComponent(props.token)}?redirect=/footy/profile`;
28	    const redirect = new URL(redirectPath, 'http://localhost').toString();
29	
30	    beforeEach(() => {
31	        vi.useFakeTimers({ shouldAdvanceTime: true });
32	        vi.clearAllMocks();
33	        captureUnexpectedErrorMock.mockResolvedValue(undefined);
34	        mockPush = vi.fn();
35	        vi.mocked(useRouter).mockReturnValue({
36	            push: mockPush,
37	            replace: vi.fn(),
38	            back: vi.fn(),
39	            forward: vi.fn(),
40	            refresh: vi.fn(),
41	            prefetch: vi.fn(),
42	        });
43	    });
44	
45	    afterEach(() => {
46	        vi.clearAllTimers();
47	        vi.useRealTimers();
48	    });
49	
50	    it('renders the form with the provided name and email', () => {
51	        render(
52	            <Wrapper>
53	                <ClaimSignup {...props} />
54	            </Wrapper>,
55	        );
56	
57	        expect(screen.getByRole('button', { name: /Create login/i })).toBeInTheDocument();
58	    });
