import { Paper } from '@mantine/core';
import z from 'zod';

import { ClaimSignup } from '@/components/ClaimSignup/ClaimSignup';

interface PageProps {
    searchParams?: Promise<{
        name?: string;
        email?: string;
        token?: string;
        error?: string;
    }>;
}

export const metadata = { title: 'Sign Up' };

const Page = async ({ searchParams: sp }: PageProps) => {
    const searchParams = await sp;
    const { name, email, token, error } = searchParams ?? {};
    const validatedEmail = z.email().safeParse(email);
    let errorMessage: string | undefined;

    if (!errorMessage && (!email || !name || !token || !validatedEmail.success)) {
        errorMessage = 'Missing or invalid invitation details.';
    }

    return (
        <Paper w="100%" maw="35rem" p="xl">
            <ClaimSignup
                name={name ?? ''}
                email={email ?? ''}
                token={token ?? ''}
                error={errorMessage ?? error}
            />
        </Paper>
    );
};

export default Page;

