    const { name, email, token } = searchParams ?? {};

    return (
        <Paper w="100%" maw="35rem" p="xl">
            <ClaimSignup
                name={name ?? ''}
                email={email ?? ''}
                token={token ?? ''}
            />
        </Paper>
    );
};

export default Page;

